import{_ as e,o as a,c as s,ag as i}from"./chunks/framework.CT-gmSiP.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/architecture.md","filePath":"en/guide/architecture.md"}'),r={name:"en/guide/architecture.md"};function n(d,t,o,c,l,p){return a(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="clean-architecture-net-9" tabindex="-1">Clean Architecture .NET 9 <a class="header-anchor" href="#clean-architecture-net-9" aria-label="Permalink to &quot;Clean Architecture .NET 9&quot;">​</a></h2><p>RIVORA Framework follows a strict layered architecture with 47 projects:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Presentation (API)           Controllers, Minimal APIs, gRPC, SignalR, GraphQL</span></span>
<span class="line"><span>       |</span></span>
<span class="line"><span>Application (CQRS)          Commands, Queries, Validators, DTOs (MediatR)</span></span>
<span class="line"><span>       |</span></span>
<span class="line"><span>Domain (Business)            Entities, Value Objects, Domain Events, Specifications</span></span>
<span class="line"><span>       |</span></span>
<span class="line"><span>Infrastructure (Data)       EF Core 9, Repositories, External Services</span></span></code></pre></div><p><strong>Fundamental rule</strong>: dependencies always point inward. Domain depends on nothing. Infrastructure depends on Domain and Application, never the reverse.</p><h2 id="project-structure" tabindex="-1">Project Structure <a class="header-anchor" href="#project-structure" aria-label="Permalink to &quot;Project Structure&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Projects</th><th>Role</th></tr></thead><tbody><tr><td><strong>Core</strong></td><td><code>Core</code>, <code>Domain</code></td><td>Abstractions, entities, events, specifications</td></tr><tr><td><strong>Application</strong></td><td><code>Application</code></td><td>CQRS (MediatR), services, validators, DTOs</td></tr><tr><td><strong>Infrastructure</strong></td><td><code>Infrastructure</code>, <code>Data.*</code> (4 providers)</td><td>EF Core, repositories, external services</td></tr><tr><td><strong>Presentation</strong></td><td><code>Api</code>, <code>GraphQL</code>, <code>Admin</code>, <code>RealTime</code></td><td>REST, GraphQL, Blazor, SignalR</td></tr><tr><td><strong>Security</strong></td><td><code>Security</code>, <code>Identity.Pro</code></td><td>JWT, BCrypt, 2FA, Rate Limiting, Audit</td></tr><tr><td><strong>Multi-Tenancy</strong></td><td><code>MultiTenancy</code>, <code>SaaS</code></td><td>Tenant isolation, billing</td></tr><tr><td><strong>Cross-Cutting</strong></td><td><code>Caching</code>, <code>Jobs.*</code>, <code>HealthChecks</code>, <code>Notifications</code>, <code>Storage</code></td><td>Cross-cutting modules</td></tr><tr><td><strong>AI</strong></td><td><code>AI</code>, <code>NaturalQuery</code></td><td>RAG, vector store, NL Query Builder</td></tr><tr><td><strong>Integration</strong></td><td><code>Export</code>, <code>Webhooks</code>, <code>Client</code></td><td>PDF/Excel/CSV, SaaS webhooks, typed API client</td></tr><tr><td><strong>DevOps</strong></td><td><code>AppHost</code>, <code>ServiceDefaults</code></td><td>.NET Aspire orchestration</td></tr><tr><td><strong>Tools</strong></td><td><code>RVR.CLI</code>, <code>RVR.Studio</code></td><td>CLI scaffolding + AI, visual IDE</td></tr></tbody></table><h2 id="modularity" tabindex="-1">Modularity <a class="header-anchor" href="#modularity" aria-label="Permalink to &quot;Modularity&quot;">​</a></h2><p>Each module implements <code>IRvrModule</code> for standardized registration:</p><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">builder.Services.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddRvrModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">CachingModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;(builder.Configuration);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">builder.Services.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddRvrModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SecurityModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;(builder.Configuration);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">builder.Services.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddRvrModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">MultiTenancyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;(builder.Configuration);</span></span></code></pre></div><p>This approach allows scaling from a modular monolith to microservices without major refactoring.</p>`,11)])])}const g=e(r,[["render",n]]);export{u as __pageData,g as default};
